/** 百万円表記。1000百万円以上は「億」に丸める。 */
export function fmtJpyMM(mm: number): string {
  if (mm >= 100) {
    const oku = mm / 100
    return `${oku % 1 === 0 ? oku.toFixed(0) : oku.toFixed(1)}億円`
  }
  return `${mm.toLocaleString("ja-JP")}百万円`
}

/** 予算レンジ表記。 */
export function fmtBudget(min: number, max: number): string {
  return `${fmtJpyMM(min)} 〜 ${fmtJpyMM(max)}`
}

/** 適合度→ステータスバッジの variant 名（Badge variant に対応）。 */
export function scoreToBadge(score: number): "success" | "info" | "warning" | "secondary" {
  if (score >= 85) return "success"
  if (score >= 70) return "info"
  if (score >= 55) return "warning"
  return "secondary"
}

