function matchIndustry(deal: SellDeal, chip: string): boolean {
  if (chip === "all") return true
  if (chip === "製造") return /金属|製造|加工/.test(deal.industry)
  if (chip === "物流") return /物流|貨物|3PL/.test(deal.industry)
  if (chip === "IT") return /情報|受託|SES/.test(deal.industry)
  if (chip === "調剤") return /調剤|薬局/.test(deal.industry)
  if (chip === "介護") return /介護/.test(deal.industry)
  return true
}

