export function MAMatchingConsole() {
  const [industry, setIndustry] = React.useState("all")
  const [area, setArea] = React.useState<(typeof AREA_OPTIONS)[number]>("all")
  const [selectedDealId, setSelectedDealId] = React.useState<string>(SELL_DEALS[0].id)
  const [selectedBuyerId, setSelectedBuyerId] = React.useState<string>(
    MATCHES[SELL_DEALS[0].id][0].buyerId
  )

  const filteredDeals = React.useMemo(
    () =>
      SELL_DEALS.filter(
        (d) => matchIndustry(d, industry) && (area === "all" || d.area.includes(area))
      ),
    [industry, area]
  )

  // 選択中の売り手が絞り込みで消えたら先頭に寄せる
  React.useEffect(() => {
    if (filteredDeals.length === 0) return
    if (!filteredDeals.some((d) => d.id === selectedDealId)) {
      const next = filteredDeals[0]
      setSelectedDealId(next.id)
      const firstMatch = MATCHES[next.id]?.[0]
      if (firstMatch) setSelectedBuyerId(firstMatch.buyerId)
    }
  }, [filteredDeals, selectedDealId])

  const selectedDeal = SELL_DEALS.find((d) => d.id === selectedDealId)
  const candidateMatches: Match[] = selectedDeal ? MATCHES[selectedDeal.id] ?? [] : []
  const selectedMatch =
    candidateMatches.find((m) => m.buyerId === selectedBuyerId) ?? candidateMatches[0]
  const selectedBuyer = selectedMatch ? buyerById(selectedMatch.buyerId) : undefined

  const handleSelectDeal = React.useCallback((deal: SellDeal) => {
    setSelectedDealId(deal.id)
    const first = MATCHES[deal.id]?.[0]
    if (first) setSelectedBuyerId(first.buyerId)
  }, [])

  // ── 売り手案件一覧（DataTable） ──
  const dealColumns = React.useMemo<ColumnDef<SellDeal>[]>(
    () => [
      {
        accessorKey: "id",
        header: "案件ID",
        cell: ({ row }) => (
          <span className="font-mono text-xs font-medium">{row.original.id}</span>
        ),
      },
      {
        accessorKey: "nickname",
        header: "案件（ノンネーム）",
        cell: ({ row }) => (
          <div className="min-w-0">
            <div className="truncate font-medium">{row.original.nickname}</div>
            <div className="truncate text-xs text-muted-foreground">{row.original.industry}</div>
          </div>
        ),
      },
      { accessorKey: "area", header: "エリア" },
      {
        accessorKey: "revenue",
        header: "売上規模",
        cell: ({ row }) => (
          <span className="tabular-nums">{fmtJpyMM(row.original.revenue)}</span>
        ),
      },
      {
        accessorKey: "askingPrice",
        header: "譲渡希望価格",
        cell: ({ row }) => (
          <span className="tabular-nums font-medium">{fmtJpyMM(row.original.askingPrice)}</span>
        ),
      },
      {
        accessorKey: "status",
        header: "ステータス",
        cell: ({ row }) => (
          <Badge variant={STATUS_BADGE[row.original.status]}>{row.original.status}</Badge>
        ),
      },
      {
        id: "candidates",
        header: "候補数",
        cell: ({ row }) => (
          <span className="tabular-nums text-muted-foreground">
            {(MATCHES[row.original.id] ?? []).length}件
          </span>
        ),
      },
    ],
    []
  )

  // ── マッチング候補（Leaderboard, score 降順） ──
  const leaderboardItems: LeaderboardItem[] = candidateMatches.map((m) => {
    const buyer = buyerById(m.buyerId)
    return {
      id: m.buyerId,
      label: buyer?.name ?? m.buyerId,
      sublabel: `${buyer?.industry ?? ""}・${buyer?.area ?? ""}`,
      value: m.score,
      valueLabel: `${m.score}`,
      tone:
        m.score >= 85 ? "success" : m.score >= 70 ? "info" : m.score >= 55 ? "warning" : "muted",
      trailing: <Tag variant="outline" size="sm">{m.buyerId}</Tag>,
      onSelect: () => setSelectedBuyerId(m.buyerId),
    }
  })

  return (
    <div className="space-y-6">
      {/* KPI ストリップ */}
      <StatGroup items={KPIS} cols={{ base: 2, md: 4 }} />

      {/* 絞り込み */}
      <Card>
        <CardContent className="space-y-3 pt-6">
          <FilterChips
            aria-label="業種で絞り込み"
            items={INDUSTRY_CHIPS}
            value={industry}
            onValueChange={setIndustry}
          />
          <div className="flex flex-wrap items-center gap-3">
            <label className="flex items-center gap-2 text-sm">
              <span className="text-muted-foreground">エリア</span>
              <Select
                aria-label="エリアで絞り込み"
                value={area}
                onChange={(e) => setArea(e.target.value as (typeof AREA_OPTIONS)[number])}
                className="w-40"
              >
                <option value="all">すべてのエリア</option>
                <option value="東海">東海</option>
                <option value="関東">関東</option>
                <option value="関西">関西</option>
                <option value="九州">九州</option>
              </Select>
            </label>
            <span className="text-xs text-muted-foreground">
              {filteredDeals.length}件 / 全{SELL_DEALS.length}件
            </span>
          </div>
        </CardContent>
      </Card>

      {/* 売り手案件一覧 */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">譲渡案件（売り手）一覧</CardTitle>
          <p className="text-sm text-muted-foreground">
            行を選択すると、その案件の買い手候補が右に表示されます。
          </p>
        </CardHeader>
        <CardContent>
          {filteredDeals.length === 0 ? (
            <EmptyState
              title="該当する案件がありません"
              description="業種・エリアの絞り込みを緩めてください。"
            />
          ) : (
            <DataTable
              columns={dealColumns}
              data={filteredDeals}
              filter={null}
              pageSize={10}
              onRowClick={handleSelectDeal}
              getRowState={(row) => (row.id === selectedDealId ? "selected" : undefined)}
            />
          )}
        </CardContent>
      </Card>

      {/* マッチング候補 + マッチ詳細 */}
      {selectedDeal && (
        <div className="grid grid-cols-1 gap-6 xl:grid-cols-[minmax(320px,420px)_1fr]">
          {/* 候補ランキング */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">
                買い手候補 — {selectedDeal.nickname}
              </CardTitle>
              <p className="text-sm text-muted-foreground">
                適合度（業種/エリア/規模/価格/シナジー）の高い順
              </p>
            </CardHeader>
            <CardContent>
              {leaderboardItems.length === 0 ? (
                <EmptyState title="候補がありません" description="ソーシングを継続中です。" />
              ) : (
                <Leaderboard
                  label="買い手候補ランキング"
                  items={leaderboardItems}
                  max={100}
                  selectedId={selectedMatch?.buyerId}
                  highlightTop={3}
                />
              )}
            </CardContent>
          </Card>

          {/* マッチ詳細（売り手 × 買い手） */}
          {selectedMatch && selectedBuyer ? (
            <PairingPanel
              deal={selectedDeal}
              buyer={selectedBuyer}
              match={selectedMatch}
              onApproach={() => {
                /* 打診ワークフロー起動（モック） */
              }}
              onNda={() => {
                /* NDA 依頼（モック） */
              }}
              onSendNonName={() => {
                /* ノンネームシート送付（モック） */
              }}
            />
          ) : (
            <Card>
              <CardContent className="pt-6">
                <EmptyState
                  title="候補を選択してください"
                  description="左のランキングから買い手候補を選ぶと、二面比較が表示されます。"
                />
              </CardContent>
            </Card>
          )}
        </div>
      )}

      <p className="text-xs text-muted-foreground">
        {ADVISORY.firm}（{ADVISORY.unit}）／ 買い手マスタ {BUY_DEALS.length}社 ・ 適合度は社内スコアリング（{scoreToBadge(95)} 等）に基づく参考値
      </p>
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  MetadataList,
  type MetadataListItem,
  Meter,
  Separator,
  Tag,
} from "@gunjo/ui"

import {
  type BuyDeal,
  type FactorGrade,
  FACTOR_SCORE,
  type Match,
  type SellDeal,
  fmtBudget,
  fmtJpyMM,
  scoreToBadge,
} from "./data"

// ──────────────────────────────────────────────────────────────────────────
// PairingPanel — 売り手 × 買い手 のマッチ詳細。
// @gunjo/ui に「会社 × 会社」を左右に並べる二面プリミティブ（MatchCard /
// PairingPanel）が無いため、ここで手組みする。RelationshipRow は from/to が
// PersonCell（アバター+氏名+役職）= 人前提なので、企業同士には使えない。
// 中身（メーター/バッジ/メタデータ/カード）はすべて gunjo 部品で構成する。
// ──────────────────────────────────────────────────────────────────────────

const FACTOR_LABELS: { key: keyof Match["factors"]; label: string; hint: string }[] = [
  { key: "industry", label: "業種", hint: "事業・業界の一致" },
  { key: "area", label: "エリア", hint: "地域・商圏の補完" },
  { key: "scale", label: "売上規模", hint: "規模の整合" },
  { key: "price", label: "価格", hint: "譲渡希望 × 予算" },
  { key: "synergy", label: "シナジー", hint: "事業シナジー仮説" },
]

const GRADE_TONE: Record<FactorGrade, "success" | "info" | "warning" | "secondary"> = {
  "◎": "success",
  "○": "info",
  "△": "warning",
  "×": "secondary",
}

function gradeText(g: FactorGrade): string {
  return { "◎": "非常に良い", "○": "良い", "△": "やや弱い", "×": "不一致" }[g]
}

/** 企業の縦カラム（売り手 or 買い手）。会社版 PersonCell が無いので手組み。 */
function EntityColumn({
  side,
  name,
  meta,
}: {
  side: "売り手（譲渡）" | "買い手（譲受）"
  name: string
  meta: MetadataListItem[]
}) {
  return (
    <div className="min-w-0 flex-1">
      <div className="mb-2 flex items-center gap-2">
        <Badge variant={side.startsWith("売り手") ? "outline" : "info"}>{side}</Badge>
      </div>
      <p className="truncate text-base font-bold tracking-tight" title={name}>
        {name}
      </p>
      <MetadataList variant="compact" items={meta} className="mt-3" />
    </div>
  )
}

export interface PairingPanelProps {
  deal: SellDeal
  buyer: BuyDeal
  match: Match
  /** 打診 / NDA / ノンネーム送付 などのアクション。 */
  onApproach?: () => void
  onNda?: () => void
  onSendNonName?: () => void
}

export function PairingPanel({
  deal,
  buyer,
  match,
  onApproach,
  onNda,
  onSendNonName,
}: PairingPanelProps) {
  const headingId = React.useId()

  const sellMeta: MetadataListItem[] = [
    { label: "業種", value: deal.industry },
    { label: "エリア", value: deal.area },
    { label: "売上高", value: fmtJpyMM(deal.revenue) },
    { label: "営業利益", value: fmtJpyMM(deal.operatingProfit) },
    { label: "EBITDA", value: fmtJpyMM(deal.ebitda) },
    { label: "従業員数", value: `${deal.employees}名` },
    { label: "譲渡希望価格", value: fmtJpyMM(deal.askingPrice) },
  ]

  const buyMeta: MetadataListItem[] = [
    { label: "業種", value: buyer.industry },
    { label: "エリア", value: buyer.area },
    { label: "直近売上高", value: buyer.revenue > 0 ? fmtJpyMM(buyer.revenue) : "—（ファンド）" },
    { label: "譲受予算", value: fmtBudget(buyer.budgetMin, buyer.budgetMax) },
    { label: "譲受の狙い", value: buyer.intent },
  ]

  return (
    <Card aria-labelledby={headingId} data-slot="pairing-panel">
      <CardHeader>
        <div className="flex flex-wrap items-center justify-between gap-3">
          <CardTitle id={headingId} className="text-base">
            マッチ詳細 — {deal.id} × {buyer.id}
          </CardTitle>
          <Badge variant={scoreToBadge(match.score)}>適合度 {match.score}</Badge>
        </div>
      </CardHeader>

      <CardContent className="space-y-5">
        {/* 二面比較：売り手（左）⟷ 買い手（右） */}
        <div className="flex items-stretch gap-4">
          <EntityColumn side="売り手（譲渡）" name={deal.nickname} meta={sellMeta} />
          <div
            className="flex shrink-0 select-none flex-col items-center justify-center px-1 text-muted-foreground"
            aria-hidden="true"
          >
            <span className="text-2xl leading-none">⟷</span>
            <span className="mt-1 text-[10px] font-medium">マッチ</span>
          </div>
          <EntityColumn side="買い手（譲受）" name={buyer.name} meta={buyMeta} />
        </div>

        <Separator />

        {/* 総合適合度メーター（gunjo Meter, higher-is-better） */}
        <div>
          <Meter
            label={`${deal.id} × ${buyer.id} の適合度`}
            value={match.score}
            max={100}
            unit="%"
            target={70}
            direction="higher-is-better"
            formatValue={(v) => `適合度 ${Math.round(v)}`}
          />
          <p className="mt-1 text-xs text-muted-foreground">
            目標ライン 70 以上で「提案推奨」。{match.note}
          </p>
        </div>

        {/* ファクター別 内訳（業種/エリア/規模/価格/シナジー）。
            会社×会社のファクター・マトリクスに当たる gunjo 部品が無いため手組み。
            各セルは gunjo の Tag + Meter(inline) で構成。 */}
        <div>
          <p className="mb-2 text-sm font-semibold">ファクター別 内訳</p>
          <ul className="grid grid-cols-1 gap-2 sm:grid-cols-2 lg:grid-cols-5" role="list">
            {FACTOR_LABELS.map(({ key, label, hint }) => {
              const grade = match.factors[key]
              return (
                <li
                  key={key}
                  className="rounded-lg border border-border bg-card p-2.5"
                >
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-medium text-muted-foreground">{label}</span>
                    <Tag variant="outline" size="sm" aria-label={`${label}：${gradeText(grade)}`}>
                      {grade}
                    </Tag>
                  </div>
                  <Meter
                    className="mt-2"
                    size="inline"
                    showValue={false}
                    label={`${label}の適合`}
                    value={FACTOR_SCORE[grade]}
                    max={4}
                    direction="fill-is-good"
                    tone={GRADE_TONE[grade] === "secondary" ? "muted" : GRADE_TONE[grade] === "info" ? "info" : GRADE_TONE[grade] === "warning" ? "warning" : "success"}
                  />
                  <p className="mt-1 text-[10px] leading-tight text-muted-foreground">{hint}</p>
                </li>
              )
            })}
          </ul>
        </div>

        <Separator />

        {/* アクション：打診 / NDA / ノンネーム送付 */}
        <div className="flex flex-wrap items-center gap-2">
          <Button variant="primary" onClick={onApproach}>
            打診する
          </Button>
          <Button variant="outline" onClick={onNda}>
            NDA を依頼
          </Button>
          <Button variant="ghost" onClick={onSendNonName}>
            ノンネームシート送付
          </Button>
          <span className="ml-auto text-xs text-muted-foreground">
            担当：{deal.advisor}
          </span>
        </div>
      </CardContent>
    </Card>
  )
}
